quirk.good:
// Shell writes a relative path
sh "git diff origin/main...HEAD > git-diff.txt"

// Bob is told the same relative path
def analysis = askBob(
    "Read git-diff.txt and tell me what changed in this PR.",
    'pipeline-git-diff-overview'
)

quirk.bad:
// Bob will refuse — '/workspace/git-diff.txt' is outside its subtree
sh "git diff origin/main...HEAD > /workspace/git-diff.txt"
def analysis = askBob(
    "Read /workspace/git-diff.txt and tell me what changed in this PR.",
    'pipeline-git-diff-overview'
)
